// // This module decodes the inputs to produce an output X based on the following conditions:
// - If A1 is high and A2 is low, X will be B2
// - If A1 is low and A2 is high, X will be B1
// - If both A1 and A2 are high, X will be C1
// - Otherwise, X will be 1'b0
module top_module(
    X ,
    A1,
    A2,
    B1,
    B2,
    C1
);output X ;
    input  A1;
    input  A2;
    input  B1;
    input  B2;
    input  C1;

    assign X = (A1 & ~A2) ? B1 :
               (~A1 & A2) ? B2 :
               (A1 & A2) ? C1 : 1'b0;

endmodule

